INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('marcus_brisolla', '{"name":"Marcus Vinicius Machado ziolkowski","mapped_name":"marcus_brisolla","birth_date":"2011-11-11","profession":"Estudante","sports_history":"Fraturou o pé no futebol/campeão da coxa cup sub-13/ medalhista na copa Paraná de judô","injuries":["Dor esporádica no calcaneo"],"health_conditions":["Boa saude"],"medications":["Nao"],"current_practice":"Ha 11 anos/ futebol e judô","goal":"Estética/performance no esporte","weekly_frequency":5,"session_duration":null,"gender":"M","experience_level":"intermediário","form_timestamp":"2025/02/20 6:32:32 PM GMT-3"}'::jsonb, '{"A":{"focus":"","exercises":[{"name":"Puxada Frente Neutra","method":"Tradicional","sets":1,"interval":"1''30\"","observations":"Utilizar o triângulo, fazer a pedada com o dedo mínimo encostando na haste lateral do triângulo."},{"name":"Agachamento Cálice (Goblet Squat)","method":"Tradicional","sets":1,"weight":"1 Halter de Aprox. 16kg","interval":"1''30\"","observations":"Segurar este halter com ambas as mãos encostando os 2 punhos, formando um \"cálice\" com os seus antebraços"},{"name":"Remada Serrote Halter","method":"Tradicional","sets":1,"reps":"8 / 8","interval":"1''30\"","observations":"Realizar uma leve rotação das mãos a cada repetição"},{"name":"Cadeira Abdutora","method":"Tradicional","sets":2,"reps":"10-15","interval":"1''30\""},{"name":"Rosca Banco 45°","method":"Tradicional","sets":2,"weight":"2 halteres de aprox. 7kg","interval":"1''30\"","observations":"Deitar em um banco a 45°, segurar ambos os halteres e fazer o movimento de rosca tentando manter os braços (úmero) na vertical em relação ao solo."},{"name":"Rotação de Tronco Polia Média (CORE)","method":"Tradicional","sets":1,"weight":"Aprox. 4 blocos","interval":"1''","observations":"Utilizar uma manopla simples, posicionar a polia do crossover na altura do seu peito, gere tensão no cabo tirando os blocos da inércia. Com os cotovelos estendidos faça uma rotação do seu tronco para o lado oposto ao cross, como se fosse realizar uma rebatida no tenis, foque toda a força dessa rotação nas laterais do seu abdômen."},{"name":"Abdominal Curto Máquina Italiana","method":"Tradicional","sets":1,"reps":"10.0","weight":"42,5 (progredir a partir daqui)","interval":"1''","observations":"Ajustar bem o apoio dos ombros, realizar a maior flexão do tronco possível, se conseguir encostar os cotovelos nos joelhos"}]},"B":{"focus":"","exercises":[{"name":"Supino Inclinado Halteres","method":"Tradicional","sets":1,"weight":"Aprox. 14kg cada halter","interval":"1''30","observations":"Banco a mais ou menos 45°, fazer o mesmo movimento do supino."},{"name":"Deadlift","method":"Tradicional","sets":1,"weight":"55kg (total)","interval":"1''30\"","observations":"Lombar sempre em posição neutra, maior parte do peso do corpo fica nos calcanhares"},{"name":"Elevação Lateral Halteres","method":"Tradicional","sets":2,"weight":"5/6kg cada halter","interval":"1''30\"","observations":"Em pé, realizar a elevação lateral dos halteres com os cotovelos estendidos o tempo todo, não encostar nas coxas ao longo da série para não perder a tensão. O movimento acontece levemente na diagonal."},{"name":"Mesa Flexora","method":"Tradicional","sets":1,"weight":"Aprox. 30kg","interval":"1''30\"","observations":"Deitado decúbito ventral (barriga p/ baixo), colocar o aparador no tendão de aquiles. Flexionar os joelhos a 90°, não passe disso para não tirar a frente do quadril do contato com a mesa flexora."},{"name":"Tríceps Testa Barra W","method":"Tradicional","sets":2,"weight":"Aprox. 15kg","interval":"1''30\"","observations":"Utilizar a barra W pronta na parte de pesos livres. Deitado em um banco, pegada na largura dos seus ombros, a barra começa acima da sua cabeça, flexione os cotovelos até que ela chegue perto da sua testa. Tente não \"abrir\" os cotovelos para os lados e nem mexa os braços, o movimento acontece em \"parábola\" na vista lateral."},{"name":"Aviãozinho c Halter","method":"Tradicional","sets":2,"weight":"Aprox. 8kg","interval":"1''","observations":"Leve flexão de joelho no final de cada repetição para explorar a maior amplitude possível.\nSegurar o halter na mão oposta a perna que esteja fazendo o exercício."}]},"C":{"focus":"","exercises":[{"name":"Crucifixo Inverso Máquina","method":"Tradicional","sets":2,"weight":"Menos carga que o anterior","interval":"1''30","observations":"Ao contrário, agora mexa no ajuste superior da máquina e sente de frente para o encosto, você vai fazer a pegada na frente do corpo e abrir os braços para trás, fazendo força bem no meio das costas (trapézios e rombóides)."},{"name":"Pulldown Polia Alta (Corda)","method":"Tradicional","sets":1,"weight":"Aprox. 7 blocos","interval":"1''30\"","observations":"Prenda uma corda na polia alta, segure-a e dê 2 passos para trás, deixe o seu tronco inclinado à frente a aprox. 45°.  Agora, tentando manter os cotovelos estendidos, você realizará uma \"parábola\", trazendo a corda para baixo e para trás, em direção ao seu quadril."},{"name":"Panturrilha Joelho Estendido","method":"Tradicional","sets":2,"reps":"12-16","weight":"Aprox. 15kg cada lado","interval":"1''","observations":"Fazer o alongamento completo das panturrilhas a cada repetição."},{"name":"Rosca Punho Invertida","method":"Tradicional","sets":1,"reps":"12-16","weight":"Aprox. 15kg (barras prontas)","interval":"1''","observations":"Sentado, apoie os antebraços nas coxas e joelhos segurando a barra com as palmas das mãos para baixo. Agora flexione os punhos o máximo possível (alongando), deixando as mãos livres para descerem à frente dos seus joelhos, e faça a contração estendendo os punhos o mais alto possível subindo a carga acima da altura dos joelhos (como se estivesse acelerando uma moto). "},{"name":"Landmine Press Ajoelhado","method":"Tradicional","sets":1,"reps":"8 / 8","weight":"Aprox. 15kg em anilhas ","interval":"1''","observations":"Procure o apoio da remada cavalinho. Coloque lá uma barra grande, essa barra ficará com a ponta fixa no chão. Adicione 10 ou 15kg em anilhas. Agora, com o joelho direito no chão (colchonete), você vai segurar a ponta da barra somente com a mão direita (mesmo lado do joelho no chão), e fazer um movimento de empurrar para cima e levemente para a frente, volte a barra ao ombro para iniciar a próxima repetição. "}]},"D":{"focus":"","exercises":[]},"E":{"focus":"","exercises":[]}}'::jsonb, ARRAY['A','B','C','D']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;